import{_ as t}from"./chunks/locator-healing.BjNtRxlF.js";import{_ as a,o as s,c as i,ag as o}from"./chunks/framework.CAXxHpAX.js";const r="/screenshots/failure-clusters.png",n="/screenshots/ai-diagnosis.png",b=JSON.parse('{"title":"AI diagnosis & failure clustering","description":"","frontmatter":{"title":"AI diagnosis & failure clustering","lang":"en-US"},"headers":[],"relativePath":"ai-diagnosis.md","filePath":"ai-diagnosis.md","lastUpdated":1784460848000}'),d={name:"ai-diagnosis.md"};function l(c,e,h,g,u,p){return s(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="ai-diagnosis-failure-clustering" tabindex="-1">AI diagnosis &amp; failure clustering <a class="header-anchor" href="#ai-diagnosis-failure-clustering" aria-label="Permalink to &quot;AI diagnosis &amp; failure clustering&quot;">​</a></h1><p>When a run finishes, Piwi groups related failures and — optionally — asks an LLM to explain them. The two features work together: clustering decides <em>what</em> to diagnose, AI diagnosis explains <em>why</em> it broke.</p><h2 id="failure-clustering" tabindex="-1">Failure clustering <a class="header-anchor" href="#failure-clustering" aria-label="Permalink to &quot;Failure clustering&quot;">​</a></h2><p>Failed test cases that share the same <strong>error fingerprint</strong> are grouped into a cluster automatically. Instead of scrolling through 20 unrelated stack traces, you see something like <em>&quot;20 failures, 3 root causes.&quot;</em></p><ul><li><strong>Fingerprinting</strong> normalizes error messages so that the same underlying failure groups together across tests, spec files, and runs. Volatile fragments are masked out: timeouts and other numbers, UUIDs and hashes, URLs and emails, and both the <em>expected</em> and <em>received</em> values of an assertion. Dynamic locator options (e.g. the <code>{ name: &#39;…&#39; }</code> of a table row) are masked too, so per-row failures collapse into one cluster — while the locator target itself (the test id / role) still distinguishes genuinely different failures.</li><li>Fingerprints are <strong>call-site agnostic</strong>: the failing stack frame is shown for context but doesn&#39;t split clusters, so one root cause reached from several spec files stays a single cluster.</li><li>The run detail page shows each failure group with <strong>flaky</strong> and <strong>worker-correlation</strong> heuristics, so you can tell &quot;the app is broken&quot; from &quot;worker 3 is misbehaving.&quot;</li><li>Every cluster has its own <strong>detail page</strong> with the affected tests, triage tools (status + notes), and the AI diagnosis panel.</li></ul><figure><img src="'+r+`" alt="Failure clusters tab grouping failures by normalized error signature"><figcaption>The Failure clusters tab — failures sharing an error fingerprint collapse into one row, with error type, occurrence count, and triage status.</figcaption></figure><p>Clustering is always on and requires no configuration. When the normalization algorithm is improved, existing clusters are migrated in place (re-fingerprinted from a stored sample error), so triage status, notes, and diagnoses survive the change. AI diagnosis is opt-in.</p><h3 id="semantic-merging-optional" tabindex="-1">Semantic merging (optional) <a class="header-anchor" href="#semantic-merging-optional" aria-label="Permalink to &quot;Semantic merging (optional)&quot;">​</a></h3><p>If an <strong>embedding</strong> model role is configured (Settings → AI), Piwi adds a semantic layer on top of the deterministic fingerprint. After a run, the clusters first seen in it are embedded and compared (cosine similarity) against the project&#39;s other open clusters; near-duplicates above <code>PIWI_CLUSTER_SIMILARITY_THRESHOLD</code> (default <code>0.92</code>) are merged into the longest-lived cluster. This catches failures that are the same root cause but phrased differently enough to dodge the fingerprint. Merges record a fingerprint alias so future occurrences attach to the survivor instead of re-forking. With no embedding role configured, clustering stays purely deterministic.</p><p>When auto-diagnose is enabled, new clusters are also given a short <strong>human-readable title</strong> (one cheap batched model call per run, using the research model when one is configured, otherwise the diagnosis model) shown in place of the raw normalized signature across the lists and the cluster page — the signature stays available on hover and below the title. Clusters fall back to the signature when no title has been generated.</p><p>Pairs that fall in the <strong>ambiguous band</strong> (similarity between <code>PIWI_CLUSTER_SUGGEST_THRESHOLD</code>, default <code>0.80</code>, and the merge threshold) aren&#39;t merged automatically. Whenever AI is configured, a model adjudicates the pair (&quot;same root cause?&quot;) — the <strong>research</strong> model when one is configured, the diagnosis model otherwise — and merges only on a high-confidence yes; when it&#39;s unsure (or no AI is configured at all), the pair becomes a <strong>merge suggestion</strong> on the project&#39;s Failure clusters tab, where a reporter or admin approves (merge) or dismisses it. Adjudication is budget-capped per run to control cost.</p><p>Embedding-based reconciliation runs after every finished run whenever an embedding role is configured — it is independent of the auto-diagnose toggle.</p><h2 id="enabling-ai-diagnosis" tabindex="-1">Enabling AI diagnosis <a class="header-anchor" href="#enabling-ai-diagnosis" aria-label="Permalink to &quot;Enabling AI diagnosis&quot;">​</a></h2><p>Configure a provider via <strong>Settings → AI</strong>, or with environment variables (env always takes precedence over values stored through the UI, and the UI shows env-managed fields read-only).</p><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_AI_PROVIDER</code></td><td><code>anthropic</code> or <code>openai</code></td></tr><tr><td><code>PIWI_AI_API_KEY</code></td><td>Provider API key (stored encrypted when set via the UI; never returned by the API)</td></tr><tr><td><code>PIWI_AI_MODEL</code></td><td>Model name (default: <code>claude-opus-4-8</code> for Anthropic)</td></tr><tr><td><code>PIWI_AI_BASE_URL</code></td><td>Base URL for OpenAI-compatible providers (e.g. Ollama, LM Studio, vLLM)</td></tr><tr><td><code>PIWI_AI_AUTO_DIAGNOSE</code></td><td><code>true</code> to automatically diagnose new clusters when a run finishes</td></tr><tr><td><code>PIWI_AI_AUTO_DIAGNOSE_MAX</code></td><td>Max clusters auto-diagnosed per finished run (budget cap; default <code>3</code>)</td></tr><tr><td><code>PIWI_AI_RESEARCH_MODEL</code> / <code>_PROVIDER</code> / <code>_BASE_URL</code> / <code>_API_KEY</code></td><td>Optional <strong>research</strong> model for two-stage diagnosis; provider/base URL/key default to the main ones</td></tr><tr><td><code>PIWI_AI_EMBEDDING_PROVIDER</code> / <code>_MODEL</code> / <code>_BASE_URL</code> / <code>_API_KEY</code></td><td>Optional <strong>embedding</strong> model for semantic failure clustering (OpenAI-compatible only — Anthropic has no embeddings API)</td></tr></tbody></table><p><code>GET /api/ai/status</code> reports whether AI is configured (without ever exposing the key); the UI uses it to show or hide AI actions.</p><h3 id="streaming-diagnosis" tabindex="-1">Streaming diagnosis <a class="header-anchor" href="#streaming-diagnosis" aria-label="Permalink to &quot;Streaming diagnosis&quot;">​</a></h3><p>Instead of waiting for a synchronous response, the diagnosis can be <strong>streamed</strong> via SSE (Server-Sent Events) — the model&#39;s reasoning tokens appear in the UI as they arrive:</p><ul><li><strong><code>POST /api/failure-clusters/[id]/diagnose/stream</code></strong> — same request body as the synchronous endpoint, but the response is a <code>text/event-stream</code> with <code>event: thinking</code> chunks containing incremental text, then a final <code>event: result</code> with the complete diagnosis.</li><li>The client uses <code>fetch()</code> with <code>POST</code> (not <code>EventSource</code>) so it can send request body params (additional context, images, base commit, etc.). The response body is read as a <code>ReadableStream</code> and parsed for SSE messages.</li><li>See the <a href="https://piwitests.github.io/demo/docs" target="_blank" rel="noreferrer">API docs</a> for the exact protocol (the in-app API reference at <code>/docs</code> shows the same spec).</li><li>In the UI, the live thinking panel shows the accumulating text with a stage indicator and auto-scroll. When the stream completes, the panel transitions to the full result card.</li></ul><h3 id="model-roles" tabindex="-1">Model roles <a class="header-anchor" href="#model-roles" aria-label="Permalink to &quot;Model roles&quot;">​</a></h3><p>Piwi calls models in up to three distinct roles, each with its own complete provider configuration (or a <strong>reuse</strong> pointer to inherit another role&#39;s provider and credentials):</p><ul><li><strong>Diagnosis</strong> — the main model that writes the final diagnosis (required to enable AI).</li><li><strong>Research</strong> — an optional cheaper/faster model that pre-analyzes the failure first (<em>two-stage diagnosis</em>).</li><li><strong>Embedding</strong> — an optional embeddings model that powers semantic failure clustering.</li></ul><p>Configure each role in <strong>Settings → AI → Model providers</strong>. A role set to <em>reuse</em> another role uses that role&#39;s provider, key, and base URL — only its model can differ — so you don&#39;t re-enter credentials for, say, a Haiku research pass on the same Anthropic key.</p><h3 id="providers" tabindex="-1">Providers <a class="header-anchor" href="#providers" aria-label="Permalink to &quot;Providers&quot;">​</a></h3><p><strong>Anthropic (recommended)</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_PROVIDER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">anthropic</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sk-ant-...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">claude-opus-4-8</span></span></code></pre></div><p><strong>OpenAI</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_PROVIDER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">openai</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sk-...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gpt-4o</span></span></code></pre></div><p><strong>OpenAI-compatible / local (Ollama, etc.)</strong> — set <code>provider</code> to <code>openai</code> and point <code>base URL</code> at the local endpoint:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_PROVIDER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">openai</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_BASE_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://localhost:11434/v1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">llama3.1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ollama</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # any non-empty value for local servers</span></span></code></pre></div><p>Use <strong>Settings → AI → Test</strong> to smoke-test the configured provider.</p><h2 id="what-a-diagnosis-contains" tabindex="-1">What a diagnosis contains <a class="header-anchor" href="#what-a-diagnosis-contains" aria-label="Permalink to &quot;What a diagnosis contains&quot;">​</a></h2><p>A diagnosis is grounded in your actual run — it is not a generic &quot;ask AI&quot; button. Each result includes:</p><ul><li><strong>Category</strong> and <strong>confidence</strong></li><li><strong>Root cause</strong> — the most likely explanation</li><li><strong>Evidence</strong> — the signals the model relied on</li><li><strong>Suggested fix</strong> and <strong>prevention tips</strong></li></ul><figure><img src="`+n+'" alt="Failure cluster page with the AI diagnosis result alongside the error and alternative locators"><figcaption>A cluster page — the AI diagnosis (category, confidence, root cause, evidence, and a suggested fix) sits beside the actual error and the ranked alternative locators it was grounded in.</figcaption></figure><h2 id="diagnosing-one-execution" tabindex="-1">Diagnosing one execution <a class="header-anchor" href="#diagnosing-one-execution" aria-label="Permalink to &quot;Diagnosing one execution&quot;">​</a></h2><p>The <a href="./ui-overview.html#failure-cluster-detail">failure cluster</a> page diagnoses a <em>group</em> of failures that share a fingerprint. When you are looking at a single failing execution, the <a href="./ui-overview.html#test-case-detail">test case detail</a> page&#39;s <strong>Diagnosis</strong> tab can diagnose <em>just that execution</em> — same model, same structured result, scoped to the one run in front of you. This is handy when a failure hasn&#39;t clustered yet, or when you want a diagnosis grounded in this specific execution&#39;s evidence rather than the cluster aggregate.</p><p>Two things are always available there, even with <strong>no provider configured</strong>:</p><ul><li><strong>Copy AI context</strong> — copies the exact evidence bundle (error, steps, console, network, ARIA snapshot, source — plus, when a trace was uploaded, the full call stack with embedded source and the trace&#39;s complete network activity — all trimmed to the <a href="#context-limits-and-token-cost">context limits</a>) so you can paste it into your own AI tool. It is the same context the model would receive.</li><li>A <strong>coverage strip</strong> showing which evidence sections are present, truncated, or absent — the same map the model sees.</li></ul><p>With a provider configured, <strong>Diagnose with AI</strong> runs the diagnosis inline and renders the result (category, confidence, root cause, evidence, suggested fix) right in the tab; cited evidence links jump to the matching section on the page. The result is stored per execution, so it survives a reload, and you can add free-text context or re-diagnose. Execution-scoped and cluster-scoped diagnoses are independent — running one never overwrites the other.</p><h2 id="scm-grounded-context" tabindex="-1">SCM-grounded context <a class="header-anchor" href="#scm-grounded-context" aria-label="Permalink to &quot;SCM-grounded context&quot;">​</a></h2><p>The real power is feeding the model the code that changed. On a cluster page you can:</p><ul><li><strong>Pin a baseline commit</strong> — the diagnosis includes the aggregate diff between that commit and the run, so the model sees what changed.</li><li><strong>Browse and cherry-pick commits</strong> — add the full diff of specific commits to the context for targeted analysis.</li><li><strong>Preview the exact context</strong> that will be sent before running (<code>GET /api/failure-clusters/[id]/context</code>), so there are no surprises about what leaves your server.</li></ul><h3 id="commit-selection-algorithm" tabindex="-1">Commit selection algorithm <a class="header-anchor" href="#commit-selection-algorithm" aria-label="Permalink to &quot;Commit selection algorithm&quot;">​</a></h3><p>When you trigger a diagnosis, Piwi determines the commit range to diff using the following priority chain:</p><ol><li><p><strong>Manual override</strong> — if you pinned a baseline commit (or the cluster has a <code>manualBaseCommit</code> saved), that commit is used as <code>fromSha</code>. This applies even in auto-diagnose and MCP-triggered diagnoses. The <code>Data Coverage</code> block in the AI context will show <code>baselineKind: manual</code>.</p></li><li><p><strong>Project-wide last-green run</strong> — Piwi looks for the most recent test run (for the same project) that finished with <code>status = &#39;passed&#39;</code> <em>before</em> the <strong>first</strong> run in which this cluster appeared (<code>firstSeenRunId</code>, not <code>lastSeenRunId</code>). Using <code>firstSeenRunId</code> gives the tightest possible causal window: the diff covers exactly the commits introduced between when the suite was last fully-green and when the failure was first observed. <code>baselineKind: run-green</code>.</p></li><li><p><strong>Per-test last-passing fallback</strong> — if no project-wide green run exists (e.g. the project is new, or CI has been failing for a long time), Piwi falls back to the last run where <em>this specific test case</em> passed. This is less precise than a project-green baseline but still vastly better than no diff. <code>baselineKind: test-green</code>.</p></li><li><p><strong>No SCM data</strong> — if none of the above yields both a baseline commit and a current commit (from the run&#39;s SCM metadata), no diff is fetched. The <code>Data Coverage</code> block marks <code>scmInvestigation</code> absent and explains why (missing repository URL, no SCM token, or a fetch error).</p></li></ol><p>The <code>coverage.scm.baselineKind</code> field is available on every diagnosis response and in the context-preview endpoint, so you can always tell which path was taken. If an SCM fetch fails, <code>coverage.scm.error</code> contains the first 300 characters of the error message.</p><h4 id="relevance-scoring" tabindex="-1">Relevance scoring <a class="header-anchor" href="#relevance-scoring" aria-label="Permalink to &quot;Relevance scoring&quot;">​</a></h4><p>Changed files are ranked by relevance to the failing test before patch text is included in the context (the patch budget is limited). The scoring signals are:</p><table tabindex="0"><thead><tr><th>Signal</th><th style="text-align:right;">Score</th></tr></thead><tbody><tr><td>Patch removes a line containing a string the test was trying to locate (smoking gun)</td><td style="text-align:right;">+8</td></tr><tr><td>Patch touches (but doesn&#39;t remove) a locator-literal string</td><td style="text-align:right;">+6</td></tr><tr><td>Test imports this file (basename match)</td><td style="text-align:right;">+5</td></tr><tr><td>Changed file IS the test file</td><td style="text-align:right;">+4</td></tr><tr><td>Changed file shares the test file&#39;s basename</td><td style="text-align:right;">+2</td></tr><tr><td>Filename token overlaps with the test title or page ARIA state</td><td style="text-align:right;">+1 each</td></tr><tr><td>File is under a source directory (<code>src/</code>, <code>lib/</code>, <code>app/</code>, …)</td><td style="text-align:right;">+1</td></tr><tr><td>File is a lockfile, doc, or config</td><td style="text-align:right;">−1</td></tr></tbody></table><p>Files scoring ≤ 2 are excluded from the &quot;Top Suspected Change&quot; callout (a low-signal hint is worse than none), but they still appear in the full changed-files list.</p><h3 id="full-source-files" tabindex="-1">Full source files <a class="header-anchor" href="#full-source-files" aria-label="Permalink to &quot;Full source files&quot;">​</a></h3><p>A diff shows only the lines that changed. To write a patch the model needs the surrounding code too, so — when SCM is reachable — Piwi also fetches the <strong>full current content</strong> of the most-suspect changed files (top-ranked by the relevance score above) and the failing test&#39;s local imports (page objects, helpers, fixtures resolved one hop from the test&#39;s <code>import</code> statements), at the commit under test. These land in a <code>Source Files</code> context section with <code>NNNN | </code> line numbers so the model can compute correct hunk headers.</p><p>Capped by <code>PIWI_AI_MAX_SOURCE_FILES</code> (default 4, set to 0 to disable) and <code>PIWI_AI_MAX_SOURCE_FILE_CHARS</code> (default 12000). Fetched over the same SCM provider API as the diff (GitHub/GitLab/Bitbucket), cached per commit SHA. The <code>coverage.sourceFiles</code> field on the context/diagnosis response lists which files were pulled in.</p><h3 id="validated-patches" tabindex="-1">Validated patches <a class="header-anchor" href="#validated-patches" aria-label="Permalink to &quot;Validated patches&quot;">​</a></h3><p>Every <code>suggestedFix.patch</code> is checked server-side, before it reaches you, against the exact source files the model was shown: Piwi parses the unified diff and dry-runs each hunk against the real file content (tolerating line-offset drift). The result is stored on the diagnosis as <code>details.patchValidation.status</code> and shown as a badge on the patch:</p><table tabindex="0"><thead><tr><th>Status</th><th>Badge</th><th>Meaning</th></tr></thead><tbody><tr><td><code>applies</code></td><td>✅ Applies cleanly</td><td>Every hunk matched at its stated position</td></tr><tr><td><code>applies-with-offset</code></td><td>⚠️ Applies with offset</td><td>Matched, but at a shifted line — <code>git apply</code> should still succeed</td></tr><tr><td><code>stale-file</code></td><td>❌ Does not apply</td><td>The file diverged from what the patch expects</td></tr><tr><td><code>invalid</code></td><td>❌ Invalid diff</td><td>The text isn&#39;t a parseable unified diff</td></tr><tr><td><code>unchecked</code></td><td>Unverified</td><td>The target file wasn&#39;t in context, so the patch couldn&#39;t be validated</td></tr></tbody></table><p>A wrong patch is worse than none, so the model is instructed to set <code>patch</code> to null unless it can quote the lines it changes from the <code>Source Files</code> / <code>Test Source</code> sections. The patch card offers <strong>Copy</strong>, <strong>Copy <code>git apply</code> command</strong>, and <strong>Download <code>.patch</code></strong>; applying is always manual (the dashboard never writes to your repository).</p><h2 id="locator-healing" tabindex="-1">Locator healing <a class="header-anchor" href="#locator-healing" aria-label="Permalink to &quot;Locator healing&quot;">​</a></h2><p>When the failure is a broken locator, the context includes an <strong>Alternative Locators</strong> section: ranked replacement locators sourced from a prior passing run (highest confidence — captured against the real DOM), from a fresh match of the renamed/moved element on the failing page, or from the failure-time ARIA snapshot. The section also names a single <strong>recommended fix</strong> — convention-preserving where the original locator style is stable enough — which the model is instructed to use verbatim in <code>suggestedFix.code</code> rather than fabricating a locator. When nothing scores as stable, it advises adding a <code>data-testid</code> to the application as the durable fix.</p><figure><img src="'+t+'" alt="Alternative locators panel with ranked replacement locators and a recommended fix"><figcaption>The Alternative locators panel — the broken locator, ranked replacements scored for stability, and a single recommended fix that preserves your locator style.</figcaption></figure><p>This evidence is generated from the locator snapshots recorded by the <a href="./capture-fixtures.html">capture fixtures</a> while tests run — make sure your specs import <code>test</code> from a fixtures file that extends <code>piwiFixtures</code>. Capture is gated by the default-on <code>captureLocators</code> reporter option. The same data drives the standalone <strong>Alternative locators</strong> panel on the test-case and cluster pages.</p><h2 id="custom-instructions" tabindex="-1">Custom instructions <a class="header-anchor" href="#custom-instructions" aria-label="Permalink to &quot;Custom instructions&quot;">​</a></h2><p>Tailor the analysis to your stack with <strong>global</strong> instructions (Settings → AI) and <strong>per-project</strong> instructions. Use them to describe your architecture, common false positives, or house style for fixes.</p><h2 id="context-limits-and-token-cost" tabindex="-1">Context limits (and token cost) <a class="header-anchor" href="#context-limits-and-token-cost" aria-label="Permalink to &quot;Context limits (and token cost)&quot;">​</a></h2><p>Every piece of evidence sent to the model costs tokens. Piwi caps each input so diagnoses stay fast and affordable. Defaults live in <code>shared/ai-context-limits.ts</code>; override them in <strong>Settings → AI</strong> or via env (env wins; the UI then shows the field read-only).</p><table tabindex="0"><thead><tr><th>Environment variable</th><th style="text-align:right;">Default</th><th>What it caps</th></tr></thead><tbody><tr><td><code>PIWI_AI_MAX_SAMPLE_ERROR_CHARS</code></td><td style="text-align:right;">10000</td><td>Characters of raw error text per error block</td></tr><tr><td><code>PIWI_AI_MAX_SCM_PATCH_BUDGET</code></td><td style="text-align:right;">15000</td><td>Total characters of diff patches across changed files</td></tr><tr><td><code>PIWI_AI_MAX_AFFECTED_TESTS</code></td><td style="text-align:right;">30</td><td>Affected tests listed</td></tr><tr><td><code>PIWI_AI_MAX_STEPS</code></td><td style="text-align:right;">50</td><td>Recent test steps included</td></tr><tr><td><code>PIWI_AI_MAX_CONSOLE_ENTRIES</code></td><td style="text-align:right;">30</td><td>Console error/warning entries</td></tr><tr><td><code>PIWI_AI_MAX_CONSOLE_ENTRY_CHARS</code></td><td style="text-align:right;">1000</td><td>Characters per console entry</td></tr><tr><td><code>PIWI_AI_MAX_NETWORK_REQUESTS</code></td><td style="text-align:right;">25</td><td>Failed network requests included</td></tr><tr><td><code>PIWI_AI_MAX_ARIA_SNAPSHOT_CHARS</code></td><td style="text-align:right;">12000</td><td>Characters of the page ARIA snapshot</td></tr><tr><td><code>PIWI_AI_MAX_TEST_SOURCE_CHARS</code></td><td style="text-align:right;">8000</td><td>Characters of the test source snippet</td></tr><tr><td><code>PIWI_AI_MAX_SOURCE_FILES</code></td><td style="text-align:right;">4</td><td>Full source files fetched from SCM to ground patches (0 disables)</td></tr><tr><td><code>PIWI_AI_MAX_SOURCE_FILE_CHARS</code></td><td style="text-align:right;">12000</td><td>Characters per fetched full source file</td></tr><tr><td><code>PIWI_AI_MAX_SERVER_LOG_ENTRIES</code></td><td style="text-align:right;">50</td><td>Backend server log entries (from the <code>X-Piwi-Logs</code> header)</td></tr><tr><td><code>PIWI_AI_MAX_SERVER_LOG_ENTRY_CHARS</code></td><td style="text-align:right;">1000</td><td>Characters per server log entry</td></tr><tr><td><code>PIWI_AI_MAX_IMAGES</code></td><td style="text-align:right;">5</td><td>Screenshots auto-included in the context</td></tr><tr><td><code>PIWI_AI_MAX_PASSED_PEERS</code></td><td style="text-align:right;">20</td><td>Passing peer tests in the same file listed</td></tr><tr><td><code>PIWI_AI_MAX_CONSOLE_WINDOW</code></td><td style="text-align:right;">50</td><td>Console entries (any level) in the window before failure</td></tr><tr><td><code>PIWI_AI_SLOW_REQUEST_MS</code></td><td style="text-align:right;">1500</td><td>Duration (ms) above which a network request is flagged as slow</td></tr><tr><td><code>PIWI_AI_MAX_TRACE_ACTIONS</code></td><td style="text-align:right;">10</td><td>Actions extracted from the Playwright trace ZIP for failing-action context (0 disables)</td></tr><tr><td><code>PIWI_AI_TRACE_DOM_CHARS</code></td><td style="text-align:right;">6000</td><td>Characters of the trace-derived DOM/ARIA excerpt</td></tr><tr><td><code>PIWI_AI_MAX_TRACE_STACK_FRAMES</code></td><td style="text-align:right;">10</td><td>Call-stack frames (with embedded-source windows) from the trace&#39;s stacks index (0 disables)</td></tr><tr><td><code>PIWI_AI_MAX_TRACE_NETWORK_REQUESTS</code></td><td style="text-align:right;">20</td><td>Requests included from the trace&#39;s network stream — failed / during-failure / slow prioritized (0 disables)</td></tr><tr><td><code>PIWI_AI_IMAGE_MAX_EDGE</code></td><td style="text-align:right;">1920</td><td>Screenshots are downscaled so their long edge is at most this many pixels before being sent</td></tr></tbody></table><h2 id="try-it-in-the-demo" tabindex="-1">Try it in the demo <a class="header-anchor" href="#try-it-in-the-demo" aria-label="Permalink to &quot;Try it in the demo&quot;">​</a></h2><p>The <a href="https://piwitests.github.io/demo/" target="_blank" rel="noreferrer">live demo</a> runs entirely in your browser with no AI provider — yet the diagnosis experience is fully wired. Several failing clusters ship with a completed diagnosis (category, confidence, evidence with citations, a validated suggested patch, per-stage pipeline stats, and auto-selected suspect commits); others are left undiagnosed so you can trigger a <strong>simulated streaming diagnosis</strong> yourself and watch the reasoning tokens arrive. The diagnoses are generated from each cluster&#39;s real seeded evidence (occurrences, failure rate, affected tests, browsers) and a canned SCM history, so the <strong>Context sent to AI</strong> modal, the data-coverage map, the commit browser, baseline pinning, and the diagnosis version history all behave as they do against a real server. Suggested-fix patches are validated against the seeded source files, so the &quot;Applies cleanly&quot; badge means the same thing it does in production.</p><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><p>API keys are encrypted at rest with <a href="./configuration.html#general"><code>PIWI_SECRET_KEY</code></a>. When you run a diagnosis, the bounded context above is sent to your configured provider — so for fully local analysis, use Ollama or another self-hosted OpenAI-compatible model and keep everything on your own infrastructure.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./configuration.html">Configuration reference</a> — all environment variables</li><li><a href="./notifications.html">Notifications</a> — subscribe to <code>cluster.new</code> and <code>diagnosis.completed</code> to get alerted when a new cluster appears or a diagnosis completes (browser, email, Slack, or webhook)</li><li><a href="./mcp.html">MCP server</a> — let AI agents query clusters and diagnoses directly</li></ul>',73)])])}const I=a(d,[["render",l]]);export{b as __pageData,I as default};
